  real<lower=0, upper=1> phi   = inv_logit(logit_phi);   // alpha / (alpha + beta)
  real<lower=0> kappa          = exp(log_kappa);         // alpha + beta
  real<lower=0> alpha          = phi * kappa;            // Beta hyperparameter
  real<lower=0> beta           = (1 - phi) * kappa;      // Beta hyperparameter
